-- V8__Insert_product_detail_translations.sql
-- 为商品详情新增 origin/specification/detail 字段的多语言翻译

INSERT INTO translations (entity_type, entity_id, field_name, language_code, translation_text) VALUES
-- Product 1
('product', 1, 'origin', 'en-US', 'Based on actual purchased product batch'),
('product', 1, 'origin', 'zh-CN', '以实际采购批次为准'),
('product', 1, 'origin', 'fr-FR', 'Selon le lot d''achat réel'),
('product', 1, 'specification', 'en-US', '2kg'),
('product', 1, 'specification', 'zh-CN', '2千克'),
('product', 1, 'specification', 'fr-FR', '2 kg'),
('product', 1, 'detail', 'en-US', 'Provence tomatoes differ from other tomato varieties with their ribbed and grooved surface, unlike smooth high-powder tomatoes. They resemble autumn persimmons or bell peppers. Due to their grooved structure, they have a hollow interior with a strawberry-like heart pattern, most noticeable in the first two layers, improving in the third and fourth layers, and rarely present in the fifth layer.'),
('product', 1, 'detail', 'zh-CN', '普罗旺斯番茄与其他番茄品种不同，表面具有条纹和沟槽，而不是光滑的高粉番茄。它们的外形类似秋日的柿子或彩椒。由于这种沟槽结构，其内部是空心的，并呈现草莓形心纹，前两层最为明显，第三、第四层逐渐平滑，第五层很少出现。'),
('product', 1, 'detail', 'fr-FR', 'Les tomates de Provence se distinguent des autres variétés par leur surface nervurée et rainurée, à l''inverse des tomates lisses riches en poudre. Elles ressemblent à des kakis d''automne ou à des poivrons. En raison de cette structure rainurée, elles possèdent un intérieur creux avec un motif en forme de cœur de fraise, très visible dans les deux premières couches, qui s''atténue dans les troisième et quatrième couches et est rarement présent dans la cinquième couche.'),

